import{_ as o,c as d,o as i,a1 as t,j as e,a,t as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"介绍: OpenCode Agent Skills | opencode-agent-skills","description":"学习 OpenCode Agent Skills 的核心价值与主要功能。掌握动态技能发现、上下文注入、压缩恢复等特性，支持 Claude Code 兼容和自动推荐。","frontmatter":{"title":"介绍: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"让 AI 懂你的技能","subtitle":"介绍: OpenCode Agent Skills","description":"学习 OpenCode Agent Skills 的核心价值与主要功能。掌握动态技能发现、上下文注入、压缩恢复等特性，支持 Claude Code 兼容和自动推荐。","tags":["入门指南","插件介绍"],"prerequisite":[],"order":1},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),r={name:"zh/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},p={tabindex:"0"};function u(s,l,c,h,g,k){return i(),d("div",null,[l[8]||(l[8]=t(`<h1 id="什么是-opencode-agent-skills" tabindex="-1">什么是 OpenCode Agent Skills？ <a class="header-anchor" href="#什么是-opencode-agent-skills" aria-label="Permalink to &quot;什么是 OpenCode Agent Skills？&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>了解 OpenCode Agent Skills 插件的核心价值</li><li>掌握插件提供的主要功能特性</li><li>理解技能如何自动发现和加载</li><li>区分本插件与其他技能管理方案的区别</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能遇到过这些情况：</p><ul><li><strong>技能分散管理困难</strong>：技能散落在项目、用户目录、插件缓存等多个位置，找不到合适的技能</li><li><strong>会话越长越麻烦</strong>：长时间会话后，之前加载的技能因上下文压缩而失效</li><li><strong>兼容性焦虑</strong>：担心从 Claude Code 迁移后，现有的技能和插件无法使用</li><li><strong>需要重复配置</strong>：每个项目都要重新配置技能，缺乏统一的技能管理机制</li></ul><p>这些问题都在影响你使用 AI 助手的效率。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> 是一个为 OpenCode 提供动态技能发现和管理能力的插件系统。</p><div class="info custom-block"><p class="custom-block-title">什么是技能？</p><p>技能（Skill）是包含 AI 工作流程指导的可复用模块。它通常是一个目录，包含 <code>SKILL.md</code> 文件（描述技能的功能和使用方法），以及可能的辅助文件（文档、脚本等）。</p></div><p><strong>核心价值</strong>：通过标准化技能格式（SKILL.md），实现跨项目、跨会话的技能复用。</p><h3 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h3><p>插件基于 TypeScript + Bun + Zod 开发，提供 4 个核心工具：</p><table tabindex="0"><thead><tr><th>工具</th><th>功能</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>将技能的 SKILL.md 内容注入到会话上下文</td></tr><tr><td><code>read_skill_file</code></td><td>读取技能目录下的支持文件（文档、配置等）</td></tr><tr><td><code>run_skill_script</code></td><td>在技能目录上下文中执行可执行脚本</td></tr><tr><td><code>get_available_skills</code></td><td>获取当前可用的技能列表</td></tr></tbody></table><h2 id="主要功能特性" tabindex="-1">主要功能特性 <a class="header-anchor" href="#主要功能特性" aria-label="Permalink to &quot;主要功能特性&quot;">​</a></h2><h3 id="_1-动态技能发现" tabindex="-1">1. 动态技能发现 <a class="header-anchor" href="#_1-动态技能发现" aria-label="Permalink to &quot;1. 动态技能发现&quot;">​</a></h3><p>插件会从多个位置自动发现技能，按优先级排序：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (项目级 - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (项目级 - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (用户级 - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (用户级 - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (插件缓存)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (已安装插件)</span></span></code></pre></div><p><strong>规则</strong>：第一个匹配的技能生效，后续同名技能被忽略。</p><blockquote><p>为什么这样设计？</p><p>项目级技能优先于用户级技能，这样你可以在项目中定制特定行为，而不会影响全局配置。</p></blockquote><h3 id="_2-上下文注入" tabindex="-1">2. 上下文注入 <a class="header-anchor" href="#_2-上下文注入" aria-label="Permalink to &quot;2. 上下文注入&quot;">​</a></h3><p>当你调用 <code>use_skill</code> 时，技能内容以 XML 格式注入到会话上下文：</p><ul><li><code>noReply: true</code> - AI 不会对注入的消息做出响应</li><li><code>synthetic: true</code> - 标记为系统生成的消息（不在 UI 显示，不计入用户输入）</li></ul><p>这意味着技能内容会持久存在于会话上下文中，即使会话增长并发生上下文压缩，技能仍然可用。</p><h3 id="_3-压缩恢复机制" tabindex="-1">3. 压缩恢复机制 <a class="header-anchor" href="#_3-压缩恢复机制" aria-label="Permalink to &quot;3. 压缩恢复机制&quot;">​</a></h3><p>当 OpenCode 执行上下文压缩时（长时间会话常见操作），插件会监听 <code>session.compacted</code> 事件，自动重新注入可用技能列表。</p><p>这确保了 AI 在长时间会话中始终知道有哪些技能可用，不会因为压缩而丢失技能访问能力。</p><h3 id="_4-claude-code-兼容" tabindex="-1">4. Claude Code 兼容 <a class="header-anchor" href="#_4-claude-code-兼容" aria-label="Permalink to &quot;4. Claude Code 兼容&quot;">​</a></h3><p>插件完全兼容 Claude Code 的技能和插件系统，支持：</p><ul><li>Claude Code 技能（<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>）</li><li>Claude 插件缓存（<code>~/.claude/plugins/cache/...</code>）</li><li>Claude 插件市场（<code>~/.claude/plugins/marketplaces/...</code>）</li></ul><p>这意味着如果你之前使用 Claude Code，迁移到 OpenCode 后仍然可以使用现有的技能和插件。</p><h3 id="_5-自动技能推荐" tabindex="-1">5. 自动技能推荐 <a class="header-anchor" href="#_5-自动技能推荐" aria-label="Permalink to &quot;5. 自动技能推荐&quot;">​</a></h3><p>插件会监控你的消息，使用语义相似度检测是否与某个可用技能相关：</p><ul><li>计算消息的 embedding 向量</li><li>与所有技能的描述计算余弦相似度</li><li>当相似度超过阈值时，注入评估提示建议 AI 加载相关技能</li></ul><p>这个过程完全自动，你不需要记住技能名称或显式请求。</p><h3 id="_6-superpowers-集成-可选" tabindex="-1">6. Superpowers 集成（可选） <a class="header-anchor" href="#_6-superpowers-集成-可选" aria-label="Permalink to &quot;6. Superpowers 集成（可选）&quot;">​</a></h3><p>插件支持 Superpowers 工作流，通过环境变量启用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>启用后，插件会自动检测 <code>using-superpowers</code> 技能，并在会话初始化时注入完整的工作流指导。</p><h2 id="与其他方案对比" tabindex="-1">与其他方案对比 <a class="header-anchor" href="#与其他方案对比" aria-label="Permalink to &quot;与其他方案对比&quot;">​</a></h2>`,40)),e("table",p,[l[7]||(l[7]=e("thead",null,[e("tr",null,[e("th",null,"方案"),e("th",null,"特点"),e("th",null,"适用场景")])],-1)),e("tbody",null,[l[4]||(l[4]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"动态发现、压缩恢复、自动推荐"),e("td",null,"需要统一管理和自动推荐的场景")],-1)),e("tr",null,[l[2]||(l[2]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[l[0]||(l[0]=a("自动注册为 ",-1)),e("code",null,"skills_"+n(s.name),1),l[1]||(l[1]=a(" 工具",-1))]),l[3]||(l[3]=e("td",null,"需要独立工具调用的场景",-1))]),l[5]||(l[5]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"完整软件开发工作流"),e("td",null,"需要严格流程规范的项目")],-1)),l[6]||(l[6]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"MCP 服务器模式"),e("td",null,"需要跨工具使用技能的场景")],-1))])]),l[9]||(l[9]=t('<p>选择本插件的理由：</p><ul><li>✅ <strong>零配置</strong>：自动发现和管理技能</li><li>✅ <strong>智能推荐</strong>：基于语义匹配自动推荐相关技能</li><li>✅ <strong>压缩恢复</strong>：长时间会话稳定可靠</li><li>✅ <strong>兼容性</strong>：无缝迁移 Claude Code 技能</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>OpenCode Agent Skills 插件通过动态发现、上下文注入、压缩恢复等核心机制，为 OpenCode 提供了完整的技能管理能力。它的核心价值在于：</p><ul><li><strong>自动化</strong>：减少手动配置和记忆技能名称的负担</li><li><strong>稳定性</strong>：长时间会话中技能始终可用</li><li><strong>兼容性</strong>：与现有 Claude Code 生态无缝集成</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../installation/">安装 OpenCode Agent Skills</a></strong>。</p><p>你会学到：</p><ul><li>如何在 OpenCode 配置中添加插件</li><li>如何验证插件是否正确安装</li><li>本地开发模式的设置方法</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>插件入口和功能概述</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>核心功能特性列表</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>技能发现优先级</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>合成消息注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>压缩恢复机制</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>语义匹配模块</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>：使用的 embedding 模型</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>：语义相似度阈值</li><li><code>TOP_K = 5</code>：自动推荐返回的技能数量上限</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>discoverAllSkills()</code>：从多个位置发现技能</li><li><code>use_skill()</code>：将技能内容注入到会话上下文</li><li><code>matchSkills()</code>：基于语义相似度匹配相关技能</li><li><code>injectSyntheticContent()</code>：注入合成消息到会话</li></ul></details>',10))])}const C=o(r,[["render",u]]);export{m as __pageData,C as default};
